#include<bits/stdc++.h>
using namespace std;
struct student{
	char name[35];
	int sui;
} a[110];
struct studenta{
	char id[35];
	int y;
}b[110];
int n;
int main()
{
	scanf("%d",&n);
	for(int i=1;i<=n;i++)
	{
		scanf("%s",a[i].name);
		scanf("%d",&(a[i].sui));
		strcpy(b[i].id,a[i].name);
		b[i].y=a[i].sui;
	}
	for(int i=n;i>=1;i--)
	{
		for(int j=1;j<=i;j++)
		{
			if(a[j].sui<a[j+1].sui)
			{
				swap(a[j],a[j+1]);
			}
		}
	}
	for(int i=1;i<=n;i++)
	{
		if(a[i].sui<60)
		{
			break;
		}
		printf("%s\n",a[i].name);
	}
	for(int i=1;i<=n;i++)
	{
		if(b[i].y<60)
		{
			printf("%s\n",b[i].id);
		}
	}
	return 0;
}
